using Microsoft.ML.Data;

namespace TicketClassifier.Models;

/// <summary>
/// Input schema for ML.NET training and prediction.
/// </summary>
public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    [ColumnName("Category")]
    public string Category { get; set; } = string.Empty;
}

/// <summary>
/// ML.NET prediction output.
/// </summary>
public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

using System.ComponentModel.DataAnnotations;

namespace TicketClassifier.Models;

public class PredictRequest
{
    [Required]
    public string Subject { get; set; } = string.Empty;

    [Required]
    public string Description { get; set; } = string.Empty;

    [Range(1, 3)]
    public int Priority { get; set; }
}

public class PredictResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> ConfidenceScores { get; set; } = new();
}

public class EvaluationMetrics
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public PerClassMetrics[] PerClassMetrics { get; set; } = [];
}

public class PerClassMetrics
{
    public string ClassName { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly EvaluationMetrics _evaluationMetrics;
    private readonly string[] _categoryLabels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Combine text features and build the classification pipeline
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        var model = pipeline.Fit(dataView);

        // Evaluate against the training data to produce metrics
        var predictions = model.Transform(dataView);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        // Extract per-class names from the label column key type
        var labelColumn = predictions.Schema["Label"];
        var keyType = (Microsoft.ML.Data.KeyDataViewType)labelColumn.Type;
        var labelBuffer = new Microsoft.ML.Data.VBuffer<ReadOnlyMemory<char>>();
        predictions.Schema["Label"].GetKeyValues(ref labelBuffer);
        _categoryLabels = labelBuffer.DenseValues()
            .Select(v => v.ToString()).ToArray();

        _evaluationMetrics = BuildMetrics(metrics, _categoryLabels);
        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(model);
    }

    public PredictResponse Predict(PredictRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(input);

        var confidenceScores = new Dictionary<string, float>();
        for (var i = 0; i < _categoryLabels.Length; i++)
        {
            confidenceScores[_categoryLabels[i]] =
                i < prediction.Score.Length ? prediction.Score[i] : 0f;
        }

        return new PredictResponse
        {
            PredictedCategory = prediction.PredictedCategory,
            ConfidenceScores = confidenceScores
        };
    }

    public EvaluationMetrics GetMetrics() => _evaluationMetrics;

    private static EvaluationMetrics BuildMetrics(
        Microsoft.ML.Data.MulticlassClassificationMetrics metrics, string[] labels)
    {
        var perClass = new List<PerClassMetrics>();
        for (var i = 0; i < labels.Length; i++)
        {
            perClass.Add(new PerClassMetrics
            {
                ClassName = labels[i],
                Precision = i < metrics.PerClassPrecision.Count
                    ? metrics.PerClassPrecision[i] : 0,
                Recall = i < metrics.PerClassRecall.Count
                    ? metrics.PerClassRecall[i] : 0,
                F1Score = i < metrics.PerClassPrecision.Count
                          && i < metrics.PerClassRecall.Count
                    ? 2 * metrics.PerClassPrecision[i] * metrics.PerClassRecall[i]
                      / (metrics.PerClassPrecision[i] + metrics.PerClassRecall[i] + 1e-10)
                    : 0
            });
        }

        return new EvaluationMetrics
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
            PerClassMetrics = perClass.ToArray()
        };
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketClassifierController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    /// <summary>
    /// Predicts the category of a support ticket.
    /// </summary>
    [HttpPost("predict")]
    public ActionResult<PredictResponse> Predict([FromBody] PredictRequest request)
    {
        if (!ModelState.IsValid)
            return BadRequest(ModelState);

        var result = _classifier.Predict(request);
        return Ok(result);
    }

    /// <summary>
    /// Returns model evaluation metrics computed at startup.
    /// </summary>
    [HttpGet("metrics")]
    public ActionResult<EvaluationMetrics> GetMetrics()
    {
        return Ok(_classifier.GetMetrics());
    }
}

